import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import KartuProduk from '../components/KartuProduk';
import ModalHapus from '../components/ModalHapus';

const KATEGORI = ['semua', 'tops', 'womens-dresses', 'womens-shoes', 'mens-shirts', 'mens-shoes', 'womens-bags', 'womens-jewellery', 'sunglasses'];

export default function DaftarProduk({ produkList, loading, onHapus, onRefresh }) {
  const [kategoriAktif, setKategoriAktif] = useState('semua');
  const [produkDihapus, setProdukDihapus] = useState(null);
  const navigate = useNavigate();

  const produkTampil = produkList.filter(p =>
    kategoriAktif === 'semua' || p.category === kategoriAktif
  );

  const handleHapus = async () => {
    try {
      await onHapus(produkDihapus.id);
    } finally {
      setProdukDihapus(null);
    }
  };

  return (
    <div className="halaman">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 12, marginBottom: 20 }}>
        <div>
          <h1 className="judul-halaman">Semua Produk</h1>
          <p className="subjudul">
            {loading ? 'Memuat...' : `${produkTampil.length} produk ditemukan`}
          </p>
        </div>
        <button
          onClick={onRefresh}
          style={{ padding: '8px 16px', border: '1px solid #ddd', borderRadius: 8, background: 'white', cursor: 'pointer', fontSize: 13 }}
        >
          ↻ Refresh
        </button>
      </div>

      <div className="filter-kategori">
        {KATEGORI.map(kat => (
          <button
            key={kat}
            className={kategoriAktif === kat ? 'aktif' : ''}
            onClick={() => setKategoriAktif(kat)}
          >
            {kat === 'semua' ? 'Semua' : kat.charAt(0).toUpperCase() + kat.slice(1)}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="loading-grid">
          {Array.from({ length: 8 }).map((_, i) => (
            <div key={i} className="skeleton" />
          ))}
        </div>
      ) : produkTampil.length === 0 ? (
        <p className="teks-tengah">Tidak ada produk di kategori ini.</p>
      ) : (
        <div className="grid-produk">
          {produkTampil.map(p => (
            <KartuProduk
              key={p.id}
              produk={p}
              onEdit={() => navigate(`/edit/${p.id}`, { state: { produk: p } })}
              onHapus={setProdukDihapus}
            />
          ))}
        </div>
      )}

      <ModalHapus
        produk={produkDihapus}
        onKonfirmasi={handleHapus}
        onBatal={() => setProdukDihapus(null)}
      />
    </div>
  );
}
